vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  //MilkDrop3 Rotate Mode:
vUv = vUv.yx;
//MilkDrop3 Flip Mode:
vUv = 1-vUv;

    ret = texture(sampler_main, vUv).xyz;
    float L = lum(ret);
    float bw = clamp01(cos(L*27 + 3)*30 - 26);
    float L2 = lum(GetBlur1(vUv));
    float bw2 = clamp01(cos(L*27 + 3)*3 - 6);

    ret = vec3(.1,.6,1.1)*ret.x +
          vec3(.1,.6,.55)*ret.y +
          vec3(1.5,.6,.2)*ret.z;

    ret = ret*ret * (.5 + bw*bw2*1);

//MilkDrop3 Color Mode:
ret /= vec3(1.0,1.1,1.2);
ret -=0.1;

  fragColor = ret;
}
